export const getEventBySlug = (slug) => {
  return events.find(event => event.slug === slug);
};

export const getAllEvents = () => {
  return events.sort((a, b) => new Date(a.date.start) - new Date(b.date.start));
};

export const getUpcomingEvents = () => {
  const today = new Date();
  return events
    .filter(event => new Date(event.date.start) >= today)
    .sort((a, b) => new Date(a.date.start) - new Date(b.date.start));
};

export const getPastEvents = () => {
  const today = new Date();
  return events
    .filter(event => new Date(event.date.end) < today)
    .sort((a, b) => new Date(b.date.start) - new Date(a.date.start));
};

export const getEventsByCategory = (category) => {
  if (!category) return events;
  return events.filter(event => event.category === category);
};

/** Categories shown when the Events list "Outdoor Events" filter is active (not exact string match on "Outdoor Event"). */
export const OUTDOOR_VENUE_CATEGORIES = new Set(['Outdoor Event', 'Retreat']);

/**
 * @param {{ category: string }} event
 * @param {string} venueFilter From toolbar: 'Indoor Event' | 'Outdoor Event' (see EventsPageClient getCategoryForFilter).
 */
export const eventMatchesVenueFilter = (event, venueFilter) => {
  if (!venueFilter) return true;
  if (venueFilter === 'Outdoor Event') return OUTDOOR_VENUE_CATEGORIES.has(event.category);
  if (venueFilter === 'Indoor Event') return !OUTDOOR_VENUE_CATEGORIES.has(event.category);
  return event.category === venueFilter;
};

export const getEventsByLocation = (state) => {
  if (!state) return events;
  return events.filter(event => event.location.state === state);
};

export const generateEventSEO = (event) => {
  // Import SEO helpers dynamically to avoid circular dependencies
  const { generateEventTitle } = require('@/lib/seo-helpers');
  const { BASE_URL } = require('@/lib/seo');
  const { openGraphListingImageUrl } = require('@/lib/ogListingImage');

  const clampMeta = (s, max) => {
    if (!s || typeof s !== 'string') return '';
    const t = s.trim();
    if (t.length <= max) return t;
    return `${t.slice(0, max - 1).trimEnd()}…`;
  };
  const stripBrandSuffix = (s) => {
    if (!s || typeof s !== 'string') return '';
    return s.replace(/\s+[|–-]\s+East Coast Kink Events$/i, '').trim();
  };

  // Prefer hand-tuned SERP copy when present; the app layout adds the site brand.
  const optimizedTitle = event.seo?.title
    ? clampMeta(stripBrandSuffix(event.seo.title), 60)
    : generateEventTitle(event);
  const rawExcerpt = event.seo?.description || event.excerpt || '';
  const metaDescription = clampMeta(rawExcerpt, 160);
  const ogDescription = clampMeta(rawExcerpt, 200);
  const rawLogoUrl = event.logo;
  const ogImageUrl = openGraphListingImageUrl(rawLogoUrl);

  return {
    title: optimizedTitle,
    description: metaDescription,
    keywords: event.seo?.keywords || `${event.name}, ${event.location.city}, ${event.location.state}, kink events, BDSM`,
    openGraph: {
      title: optimizedTitle,
      description: ogDescription,
      images: [
        {
          url: ogImageUrl,
          width: 1200,
          height: 630,
          alt: event.name
        }
      ],
      type: 'website',
      url: `${BASE_URL}/events/${event.slug}`,
      siteName: 'East Coast Kink Events'
    }
  };
};
